spec.expr:
label_replace(
  max by(if_interface_name, if_Alias, if_OperStatus, if_Speed)(
    kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}
  ),
  "if_Alias", "—", "if_Alias", "^$"
)

(
  sum by(if_interface_name) (
    rate(kentik_snmp_ifHCInOctets{device_name=~"$instance", if_interface_name=~"$interface_name"}[$__rate_interval])
  ) * 8
) or (
  max by(if_interface_name) (kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}) * 0
)

(
  sum by(if_interface_name) (
    rate(kentik_snmp_ifHCOutOctets{device_name=~"$instance", if_interface_name=~"$interface_name"}[$__rate_interval])
  ) * 8
) or (
  max by(if_interface_name) (kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}) * 0
)

(
  max by(if_interface_name) (kentik_snmp_IfInUtilization{device_name=~"$instance", if_interface_name=~"$interface_name"})
) or (
  max by(if_interface_name) (kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}) * 0
)

(
  max by(if_interface_name) (kentik_snmp_IfOutUtilization{device_name=~"$instance", if_interface_name=~"$interface_name"})
) or (
  max by(if_interface_name) (kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}) * 0
)

max by(if_interface_name)(
  kentik_snmp_if_OperStatus{device_name=~"$instance", if_interface_name=~"$interface_name"}
)
and on(if_interface_name)
(
  changes(
    max by(if_interface_name)(kentik_snmp_if_OperStatus{device_name=~"$instance"})[$__range:1m]
  ) > 0
)

label_replace(
  max by(if_interface_name, if_Alias, if_OperStatus, if_Speed)(
    kentik_snmp_if_OperStatus{device_name=~"$instance"}
  ),
  "if_Alias", "—", "if_Alias", "^$"
)
